const items = $input.all(); const signals = []; const now = new Date().toISOString();
items.forEach((item) => {
  const d = item.json;
  if (d.data && Array.isArray(d.data) && d.data.length && d.data[0] && d.data[0].epsAvg !== undefined) {
    signals.push({ module:'HM1_ESTIMATE', ticker:d.symbol||'', epsAvg:d.data[0].epsAvg, period:d.data[0].period, signal_weight:'MEDIUM' });
  }
  if (Array.isArray(d) && d.length && d[0] && d[0].toGrade) {
    const ups = d.slice(0,5).filter(x=>x.action==='up').length;
    const dns = d.slice(0,5).filter(x=>x.action==='down').length;
    signals.push({ module:'HM2_ANALYST', ticker:d[0].symbol||'', upgrades:ups, downgrades:dns, signal_weight:ups>dns?'HIGH':dns>ups?'LOW':'MEDIUM' });
  }
  if (d.technicalAnalysis && d.technicalAnalysis.signal) {
    const sig = d.technicalAnalysis.signal;
    signals.push({ module:'HM3_TECH', signal:sig, buy:d.technicalAnalysis.count&&d.technicalAnalysis.count.buy||0, sell:d.technicalAnalysis.count&&d.technicalAnalysis.count.sell||0, signal_weight:(sig==='buy'||sig==='strong_buy')?'HIGH':(sig==='sell'||sig==='strong_sell')?'LOW':'MEDIUM' });
  }
  if (d.data && Array.isArray(d.data) && d.data.length && d.data[0] && d.data[0].mspr !== undefined) {
    const lat = d.data[d.data.length-1]; const mspr = lat?(lat.mspr||0):0;
    signals.push({ module:'HM12_INSIDER', ticker:d.symbol||'', mspr, signal_weight:mspr>5?'HIGH':mspr<-5?'LOW':'MEDIUM', read:mspr>5?'INSIDERS_BUYING':mspr<-5?'INSIDERS_SELLING':'NEUTRAL' });
  }
  if (d.data && Array.isArray(d.data) && d.data.length && d.data[0] && d.data[0].awardDescription) {
    const tot = d.data.reduce((s,x)=>s+(x.totalValue||0),0);
    signals.push({ module:'HM13_GOV_CONTRACT', ticker:d.symbol||'', contracts:d.data.length, total_value:tot, signal_weight:tot>1000000?'HIGH':'MEDIUM' });
  }
  if (d.data && Array.isArray(d.data) && d.data.length && d.data[0] && d.data[0].income!==undefined) {
    const tot = d.data.reduce((s,x)=>s+(x.expenses||x.income||0),0);
    signals.push({ module:'HM14_LOBBYING', ticker:d.symbol||'', filings:d.data.length, total:tot, signal_weight:tot>500000?'HIGH':'MEDIUM' });
  }
  if (d.data && Array.isArray(d.data) && d.data.length && d.data[0] && d.data[0].score !== undefined) {
    const rec = d.data.slice(-7); const avg = rec.reduce((s,x)=>s+(x.score||0),0)/(rec.length||1);
    signals.push({ module:'HM15_SOCIAL', ticker:d.symbol||'', avg_score:Math.round(avg*100)/100, signal_weight:avg>0.3?'HIGH':avg<-0.3?'LOW':'MEDIUM', sentiment:avg>0.3?'BULLISH':avg<-0.3?'BEARISH':'NEUTRAL' });
  }
  if (d.levels && Array.isArray(d.levels)) { signals.push({ module:'HM16_SR', levels:d.levels, signal_weight:'MEDIUM' }); }
  if (d.sectorExposure) { signals.push({ module:'HM11_ETF', ticker:d.symbol||'', top3:d.sectorExposure.slice(0,3), signal_weight:'MEDIUM' }); }
});
const HIGH = signals.filter(s=>s.signal_weight==='HIGH');
const tkMap = {}; signals.forEach(s=>{if(s.ticker)tkMap[s.ticker]=(tkMap[s.ticker]||0)+1;});
const top10 = Object.entries(tkMap).sort((a,b)=>b[1]-a[1]).slice(0,10).map(([t,c])=>({ticker:t,signal_count:c}));
return [{json:{micro_scan_timestamp:now, total_signals:signals.length, high_priority_count:HIGH.length, top_tickers:top10, high_signals:HIGH, all_signals:signals, modules:[...new Set(signals.map(s=>s.module))], workflow:'HUNTER_MICRO_v1.0'}}];

